esqlQuery.esql:
TS metrics-ibmmq.otel-*
| STATS cpu_load_5m = MAX(AVG_OVER_TIME(ibmmq_qmgr_cpu_load_five_minute_average_percentage))
    BY attributes.qmgr
// Alert when the 5-minute CPU load average exceeds 85%
// < 70% is healthy; 70-85% is warning; > 85% is critical
// High CPU load degrades message throughput and increases latency
// Adjust threshold based on your host capacity and co-located workloads
| WHERE cpu_load_5m IS NOT NULL AND cpu_load_5m > 85
